+void XmlMemDetailDiffReporter::report_diff() const {
+  XmlMemSummaryDiffReporter::report_diff(/*summary only*/false);
+  diff_malloc_sites();
+  diff_virtual_memory_sites();
+  xml_output()->tail("nativeMemoryTracking");
